INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-23e15ae5-moex-00220', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「葉石濤所致力的臺灣文學史的書寫工程，可謂相當艱鉅。眾所皆知，他 是戰後第一位提出『臺灣鄉土文學』主張的作家。不過，他從來沒有把『鄉 土文學』一詞視為凝滯不變的靜態名詞，而是以動態、有機的觀點，不斷 為這個名詞賦予新的內容與新的解釋。」依據這段論述，作者認為葉石濤 論述「鄉土文學」的態度是：', '["建立於艱鉅的考察省思，無法撼動", "採取彈性、寬廣的態度，不斷增修", "具有凝滯不變的穩定度，容易普及", "能顧及各方所據的立場，避免爭議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00221', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「祖上說唯此得道老鱉該得仙緣，一縷龜魂望空而去，做黃老仙師一日坐 騎。善信們無不譁然，俱言：幸哉此龜。不知誰發起的許願之想，且率先 擲了個五角硬幣，此後逢仙師誕則放生池內錢如雨下，驚得龜兒們躲入各 自的防空洞，喃喃祈禱黃老仙師打救。仙師誕後翌日，我必隨祖上下那池 中撿拾錢幣，順便清除池中穢物。祖上說善信愚昧破壞風水，染得滿池銅 臭，只有壞了龜兒的清修大事。」下列選項，何者最符合上文文意？', '["廟方為斂財，散布老龜傳說", "有人欲破壞此廟風水，製造謠言", "善信希望老龜擔任坐騎時，能將願望傳達給仙師", "善信在仙師誕辰見到老龜望空而去，為仙師一日坐騎"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00222', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「即使人們不講道理、思想謬誤、自我中心，不管怎樣，還是要愛他們。 如果你做善事，人們說你自私自利、別有用心，不管怎樣，還是要做善事。 如果你成功以後，身邊盡是假的朋友和真的敵人，不管怎樣，還是要成功。 即使你所做的善事明天就會被人遺忘，不管怎樣，還是要繼續做善事。即 使誠實與坦率使你易受攻擊，但不管怎樣，還是要誠實與坦率。就算你耗 費數年所建設的可能毀於一旦，但不管怎樣，還是要建設。需要幫助的人， 可能會反過來攻擊你，但不管怎樣，還是要幫助別人。將你所擁有最好的 東西獻給世界，即使你可能會因此受傷，但還是要將你所擁有最好的東西 獻給世界。」根據上文，下列敘述何者正確？', '["面對他人可能的攻擊，應採取以直報怨的方式處理", "即使身處險境，還是要抱持善有善報的信念，戮力前行", "面對他人批評，與其憂讒畏譏，不如擇善固執、為所當為", "身處於舉世皆濁的環境時，應採取修身見於世的方式面對"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00223', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「流水之光，星之光，露珠之光，電之光，在青年的妙目中閃耀，我們不 能不驚訝造化者藝術之神奇；然可怖的黑影，倦與衰與飽饜的黑影，同時 亦緊緊的跟著時日進行，彷彿是煩惱，痛苦，失敗，或庸俗的尾曳，亦在 轉瞬間，彗星似的掃滅了我們最自傲的神輝——流水涸，明星沒，露珠散 滅，電閃不再！」文中對青年之描述，不包括下列何者？', '["生活的腐敗", "理想的幻滅", "生存的疲憊", "志氣的消磨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00224', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「敏感而強勁，顫顫那長竿似弓，將他激射向半空，他將自己倒蹴，精巧 地蹴成一道弧——而旋腰，迴身，推竿，凌空一霎間，在勝利的頂點，他 半醒半醺飄飄然降回地面。」根據上述詩句，描述何種類型的運動？', '["標槍", "體操", "撐竿跳", "高空彈跳"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00225', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「『孩子』雖是從己身所出，卻實為獨立個體，父母既不擁有子女的所有 權，甚至沒有命令指使子女行為的資格；親與子的終極意義在於相互陪伴， 圓滿彼此的完整人生——為人子女、為人父母，扶持體驗人世間的生老病 死、紅塵中的喜怒哀樂。只是，望子成龍、望女成鳳乃人之常情，能真正 尊重並支持子女選擇的父母幾希……；但為人父母者至少可以時刻提醒自 己，成龍成鳳只有單一途徑嗎？哪些人格特質才是成龍成鳳的必備元素？ 這些人格特質又該如何養成？這些問題的具體答案或許因人而異，但總有 些共通之處可供依循，依筆者淺見：未來世界的變化肯定超乎想像，各行 各業都有機會育成人生勝利組，但想要在茫茫人海中脫穎而出，獨立思考 能力、實做解決問題、堅持永不放棄等人格特質不可或缺，而且這些素養 皆非一蹴可幾，需要長時間引導與練習方能成就。」根據上文，下列選項 最符合文意的是：', '["行業多有不同，唯有出名才算是成功", "父母應陪伴成長，尊重子女選擇方向", "子女應努力學習，以達成父母的期待", "父母應要求子女，與時偕行成為龍鳳"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00226', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '承上題，文中所謂子女的成功來自於：', '["父母的殷切期待", "父母的血緣基因", "社會的寬容保護", "良好的人格特質"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00227', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「高度工商業化使得傳統價值體系幾乎瓦解，人變成一部生產機器，工作 與生活失調，生命缺乏內涵，了無意義。衡諸今日臺灣社會，最嚴重的病 徵是失去文化自覺和生活的品味能力。不管是衣食住行育樂，都變得潦草 粗俗，一個文明社會應有的精緻的講求，深刻的感悟與審美的觀照，均為 唯實用主義的洪流淹沒。」根據上文，作者主要在感嘆：', '["現代人只講求感官享樂", "精神與物質生活的失衡", "缺乏文學內涵與鑑賞力", "失去對人的熱情與關注"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00228', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「飼養寵物，就是要好好把動物當成生命來看待，畢竟牠們不是物品，也 不會和我們有著一樣的想法。悉心疼愛、投入關注很重要。如果只憑著人 類自身的想法揣測：『我們家的孩子一定是這麼想的。』這就真的很奇怪 了。」下列選項，何者最接近上文的意涵？', '["人類時常以自己的想法推想所飼養動物的心情", "人類往往將寵物當成東西，要求他們配合自己的生活模式", "人類飼養寵物時常只是一時興起，並未將他們當成生命看待", "人類嘴巴說眾生平等，卻不將其他動物當成和我們一樣的生命看待"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00229', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「一九四二年，美國的廣告公司向余清金訂購一千萬隻的蝴蝶，為了一個 奇異的用途。他們打算在廣告信封上用玻璃紙放隻蝴蝶，以便讓民眾願意 打開信封看裡頭的廣告。沒想到夾上蝴蝶的廣告傳單效果奇佳，為了應付 逐年增加的訂單，余清金遂架構起全台的捕蝶網絡，鼎盛時期，有近兩千 個捕蝶人協助他採集標本，數百位女作業員進行加工。蝶翼完整而美麗的 通常都做成標本或其他工藝品，而蝶翼有殘缺的個體則成為蝶畫的材料。」 以上文字想傳達：', '["無用之用，是為大用", "美與醜陋僅有一線之隔", "如善於用，能提升價值效益", "竭澤而漁，蝴蝶王國盛況不再"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL)
